// Laser Light — ported from Plane9 (Joakim Dahl, CC BY-NC-SA 3.0),
// based on a shader by paulofalcao. Field math preserved; the original's
// gIn1 drift/gain inputs are driven by audio here.
//@param gain 0.05 0.6 0.22
fn makePoint(p : vec2f, fx : f32, fy : f32, t : f32) -> f32 {
  let xx = p.x * cos(t / fx);
  let yy = p.y * sin(t / fy);
  return 1.0 / (sqrt(length(vec2f(xx + yy)) + length(vec2f(xx * yy))));
}

fn render(c : Ctx) -> vec3f {
  var p = c.q * 2.0;
  // original: p -= gIn1.xy (slow drift input) — drive it from the waveform
  p -= vec2f(wav(8), wav(40)) * 0.3;
  let t = c.t;

  var a = makePoint(p, 3.3, 2.9, t);
  a += makePoint(p, 1.9, 2.0, t);
  a += makePoint(p, 0.8, 0.7, t);
  a += makePoint(p, 0.8, 1.7, t);
  a += makePoint(p, 0.3, 1.0, t);
  a += makePoint(p, 1.4, 1.7, t);
  a += makePoint(p, 1.8, 1.7, t);

  var b = makePoint(p, 1.2, 1.9, t);
  b += makePoint(p, 0.7, 2.7, t);
  b += makePoint(p, 1.4, 0.6, t);
  b += makePoint(p, 0.7, 1.4, t);
  b += makePoint(p, 0.8, 0.5, t);
  b += makePoint(p, 1.4, 0.7, t);
  b += makePoint(p, 0.7, 1.3, t);

  var d = makePoint(p, 3.7, 0.3, t);
  d += makePoint(p, 1.9, 1.3, t);
  d += makePoint(p, 0.8, 0.9, t);
  d += makePoint(p, 0.3, 0.6, t);
  d += makePoint(p, 0.3, 0.3, t);
  d += makePoint(p, 1.4, 0.8, t);
  d += makePoint(p, 0.2, 0.6, t);
  d += makePoint(p, 1.3, 0.5, t);

  // original gain gIn1.z — audio-driven here, hue-rotatable via pal()
  let raw = vec3f(a, b, d) * gain() * (0.7 + c.bass * 1.2 + c.beat * 0.5);
  let col = raw.x * pal(0.0) + raw.y * pal(0.33) + raw.z * pal(0.66);
  return col * c.intensity;
}

